// NODO: System_Error_Collection_Retrieval
// SCENARIO: Utente "Fantasma" (Startato ma dati DB persi/corrotti)
// OUTPUT: Payload Telegram (Messaggio) + Payload Webhook (JSON Error)


const item = $input.first().json;
const body = item.user_request || {};
const msg = body.message || {};
const owner = item.owner_data || {};

// 1. Recupero Dati Contesto
const chatId = owner.chat_id;
const userLang = body.lang || 'en';

// 2. Definizione Errore
const errorCode = "CRITICAL_DATA_LOSS";
const errorMessage = "Owner profile not found despite active session flag.";

