    text: "The system detects you should be an active user, but cannot retrieve your company profile.",
    reason: "Possible data corruption or accidental deletion.",
    action: "Please contact technical support providing your ID:",
    btn: "🆘 Support"
};

// 4. Costruzione Messaggio Telegram
const messageText = 
`${t.title}

${t.text}

🛑 <b>Reason:</b> ${t.reason}

👉 <b>${t.action}</b> de>${chatId}</code>`;

const telegramPayload = {
    chat_id: chatId,
    text: messageText,
    parse_mode: "HTML",
    reply_markup: {
        inline_keyboard: [[{ text: t.btn, url: "https://t.me/TrinAi_TecSupport_bot" }]]
    }
};


// 6. Return Unificato
return {
    json: {
        // Payload per il nodo HTTP (Telegram)
        telegramApiPayload: telegramPayload,

        // Flag per logica successiva n8n
        error_type: "GHOST_USER",
        is_fatal: true
    }
};
